 42→
 43→type ActiveStage = {
 44→  detail: string;
 45→  label: string;
 46→} | null;
 47→
 48→type FormatWorkspaceProps = {
 49→  activeStage: ActiveStage;
 50→  elapsedTime: string;
 51→  job: ImportJob;
 52→  view: ViewMode;
 53→  onViewChange: (view: ViewMode) => void;
 54→};
 55→
 56→function _describeSelectionLabel(selection: AdjustmentSelection) {
 57→  if (selection.lineStart !== undefined && selection.lineEnd !== undefined) {
 58→    return formatMarkdownLinesLabel(selection.lineStart, selection.lineEnd);
 59→  }
 60→
 61→  return formatMessageBlockLabel(
 62→    selection.messageRole,
 63→    selection.messageIndex + 1,
 64→    selection.blockType,
 65→  );
 66→}
 67→
 68→function renderArtifact(view: Exclude<ViewMode, "reader">, job: ImportJob) {
 69→  if (!job.artifacts) {
 70→    return "Artefakt ist noch nicht verfügbar.";
 71→  }
 72→
 73→  switch (view) {
 74→    case "markdown":
 75→      return job.artifacts.markdown;
 76→    case "handover":
 77→      return job.artifacts.handover;
 78→    case "json":
 79→      return job.artifacts.json;
 80→  }
 81→}
 82→
 83→export function FormatWorkspace({
 84→  activeStage,
 85→  elapsedTime,
 86→  job,
 87→  view,
 88→  onViewChange,
 89→}: FormatWorkspaceProps) {
 90→  const isAdjustableView = adjustableViews.has(view);
 91→
 92→  const session = useAdjustmentSession(view, job.id);
 93→  const rules = useFormatRules(view, job.id);
 94→  const snapshots = useSnapshots(job.id);
 95→  const messageEdits = useMessageEdits(job.id, snapshots.activeSnapshot?.id);
 96→  const resolvedMessages = useResolvedConversation(
 97→    job.conversation,
 98→    messageEdits.editedMessagesMap,
 99→  );
100→  const autoSnapshot = useAutoSnapshot({
101→    activeSnapshot: snapshots.activeSnapshot,
102→    create: snapshots.create,
103→    activate: snapshots.activate,
104→  });
105→  const deletion = useMessageDeletion(job.id);
106→  const deletionToast = useDeletionToast();
107→  const [editMode, setEditMode] = useState<EditMode>("view");
108→
109→  const hasEdits = resolvedMessages.some((m) => m.isEdited);
110→
111→  // beforeunload warning when unsaved edits exist
112→  useEffect(() => {
113→    if (!messageEdits.isSaving) return;
114→    const handler = (e: BeforeUnloadEvent) => {
115→      e.preventDefault();
116→    };
117→    window.addEventListener("beforeunload", handler);
118→    return () => window.removeEventListener("beforeunload", handler);
119→  }, [messageEdits.isSaving]);
120→
121→  const handleBlocksChange = useCallback(
122→    (messageId: string, blocks: Block[]) => {
123→      void autoSnapshot.ensureSnapshot().then((ready) => {
124→        if (ready) {
125→          messageEdits.saveEdit(messageId, blocks);
126→        }
127→      });
128→    },
129→    [autoSnapshot, messageEdits],
130→  );
131→  const [versionsModalOpen, setVersionsModalOpen] = useState(false);
132→  const [deleteDialog, setDeleteDialog] = useState<{
133→    messageId: string;
134→    isRound: boolean;
135→    preview: string;
136→  } | null>(null);
137→  const popover = useAdjustmentPopover();
138→
139→  const handleDeleteMessage = useCallback(
140→    (messageId: string) => {
141→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
142→      const preview =
143→        msg?.blocks
144→          .map((b) => ("text" in b ? b.text : b.type))
145→          .join(" ")
146→          .slice(0, 200) ?? messageId;
147→      setDeleteDialog({ messageId, isRound: false, preview });
148→    },
149→    [job.conversation?.messages],
150→  );
151→
152→  const handleDeleteRound = useCallback(
153→    (messageId: string) => {
154→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
155→      const preview =
156→        msg?.blocks
157→          .map((b) => ("text" in b ? b.text : b.type))
158→          .join(" ")
159→          .slice(0, 200) ?? messageId;
160→      setDeleteDialog({ messageId, isRound: true, preview });
161→    },
162→    [job.conversation?.messages],
163→  );
164→
165→  const handleConfirmDelete = useCallback(
166→    async (reason?: string) => {
167→      if (!deleteDialog) return;
168→      const { messageId, isRound } = deleteDialog;
169→      setDeleteDialog(null);
170→      if (isRound) {
171→        const result = await deletion.deleteRound(messageId, reason);
172→        deletionToast.showDeletedToast(messageId, true, result.length);
173→      } else {
174→        await deletion.deleteMessage(messageId, reason);
175→        deletionToast.showDeletedToast(messageId, false);
176→      }
177→    },
178→    [deleteDialog, deletion, deletionToast],
179→  );
180→
181→  const handleUndoDelete = useCallback(async () => {
182→    if (!deletionToast.toast) return;
183→    await deletion.restoreMessage(deletionToast.toast.messageId);
184→    deletionToast.dismissToast();
185→  }, [deletion, deletionToast]);
186→
187→  const mergedRef = useCallback(
188→    (node: HTMLElement | null) => {
189→      (
190→        session.sectionRef as React.MutableRefObject<HTMLElement | null>
191→      ).current = node;
192→      (
193→        popover.containerRef as React.MutableRefObject<HTMLElement | null>
194→      ).current = node;
195→    },
196→    [session.sectionRef, popover.containerRef],
197→  );
198→
199→  const artifact = view === "reader" ? "" : renderArtifact(view, job);
200→  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
201→  // `applyMarkdownRules` inklusive format_profile-Rules enthält. Der Server-
202→  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
203→  const displayedMarkdown = useMemo(() => {
204→    if (view !== "markdown") return artifact;
205→    try {
206→      return applyMarkdownRules(artifact, rules.activeRules);
207→    } catch {
208→      return artifact;
209→    }
210→  }, [artifact, rules.activeRules, view]);
211→
212→  const resolvedConversation = useMemo(() => {
213→    if (!job.conversation) return undefined;
214→    return {
215→      ...job.conversation,
216→      messages: resolvedMessages.map((rm) => ({
217→        id: rm.id,
218→        role: rm.role,
219→        blocks: rm.blocks,
220→      })),
221→    };
222→  }, [job.conversation, resolvedMessages]);
223→
224→  const readerEffectsMap = useMemo(
225→    () =>
226→      view === "reader" && resolvedConversation
227→        ? buildReaderEffectsMap(rules.activeRules, resolvedConversation)
228→        : new Map(),
229→    [rules.activeRules, resolvedConversation, view],
230→  );
231→
232→  const handleDownloadMarkdown = useMemo(() => {
233→    if (view !== "markdown") return undefined;
234→    return () => {
235→      const blob = new Blob([displayedMarkdown], { type: "text/markdown" });
236→      const url = URL.createObjectURL(blob);
237→      const a = document.createElement("a");
238→      a.href = url;
239→      a.download = `export-${job.id}.md`;
240→      document.body.appendChild(a);
241→      a.click();
242→      document.body.removeChild(a);
243→      setTimeout(() => URL.revokeObjectURL(url), 100);
244→    };
245→  }, [view, displayedMarkdown, job.id]);
246→  const showPopover =
247→    session.adjustModeEnabled &&
248→    Boolean(session.activeSelection) &&
249→    Boolean(session.activeAnchor);
250→
251→  const popoverCallbacksRef = useRef({
252→    handleDiscardSession: session.handleDiscardSession,
253→    activeSessionDetail: session.activeSessionDetail,
254→    handleRejectLastChange: rules.handleRejectLastChange,
255→    setReplyVisible: session.setReplyVisible,
256→  });
257→  popoverCallbacksRef.current = {
258→    handleDiscardSession: session.handleDiscardSession,
259→    activeSessionDetail: session.activeSessionDetail,
260→    handleRejectLastChange: rules.handleRejectLastChange,
261→    setReplyVisible: session.setReplyVisible,
262→  };
263→
264→  const handlePopoverClose = useCallback(() => {
265→    popoverCallbacksRef.current.handleDiscardSession();
266→  }, []);
267→
268→  const handleRejectLastChange = useCallback(() => {
269→    const {
270→      activeSessionDetail,
271→      handleRejectLastChange: reject,
272→      setReplyVisible,
273→    } = popoverCallbacksRef.current;
274→    if (activeSessionDetail) {
275→      void reject(activeSessionDetail).then((success) => {
276→        if (success) setReplyVisible(false);
277→      });
278→    }
279→  }, []);
280→
281→  const sessionError =
282→    session.activeSessionError ?? rules.disableError ?? rules.promoteError;
283→
284→  const viewErrorFallback = (_error: Error, reset: () => void) => (
285→    <div className="flex flex-col items-center justify-center gap-4 p-8 text-center">
286→      <p className="text-red-700">{miscLabels.viewLoadError}</p>
287→      <button
288→        className="rounded-lg border border-border px-4 py-2 text-sm hover:bg-foreground/5"
289→        type="button"
290→        onClick={reset}
291→      >
292→        {miscLabels.retryButton}
293→      </button>
294→    </div>
295→  );
296→
297→  return (
298→    <section
299→      ref={mergedRef}
300→      className="relative space-y-4 rounded-[1.9rem] border border-border/80 bg-background/70 p-4 sm:p-5"
301→    >
302→      <StatusHeader
303→        activeStage={activeStage}
304→        elapsedTime={elapsedTime}
305→        job={job}
306→      />
307→
308→      {job.warnings.length > 0 ? (
309→        <div className="rounded-2xl border border-amber-300/40 bg-amber-100/60 px-4 py-3 text-sm text-amber-950">
310→          {job.warnings[0]}
311→        </div>
312→      ) : null}
313→
314→      {job.status === "failed" ? (
315→        <div className="rounded-2xl border border-red-300/40 bg-red-100/70 p-4 text-red-900">
316→          <p className="font-medium">{miscLabels.importFailed}</p>
317→          {job.errorStage && job.errorStage !== "done" && (
318→            <p className="text-sm mt-1">
319→              {miscLabels.errorInPhase(getImportStageLabel(job.errorStage))}
320→            </p>
321→          )}
322→          {job.error && <p className="text-sm mt-1">{job.error}</p>}
323→        </div>
324→      ) : job.status === "queued" || job.status === "running" ? (
325→        <LoadingStateBlock stageDetail={activeStage?.detail} />
326→      ) : (
327→        <div className="space-y-4">
328→          <CompletedToolbar
329→            adjustModeEnabled={session.adjustModeEnabled}
330→            editMode={editMode}
331→            isAdjustableView={isAdjustableView}
332→            rules={rules}
333→            view={view}
334→            onDownloadMarkdown={handleDownloadMarkdown}
335→            onEditModeChange={setEditMode}
336→            onToggleAdjustMode={session.toggleAdjustMode}
337→            onViewChange={onViewChange}
338→            deletionsCount={deletion.deletionsCount}
339→            showDeleted={deletion.showDeleted}
340→            snapshotCount={snapshots.snapshots.length}
341→            onVersionsClick={() => setVersionsModalOpen(true)}
342→            onToggleShowDeleted={() =>
343→              deletion.setShowDeleted(!deletion.showDeleted)
344→            }
345→          />
346→
347→          {sessionError && !session.adjustModeEnabled ? (
348→            <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
349→              {sessionError}
350→            </div>
351→          ) : null}
352→
353→          {view === "reader" ? (
354→            <ErrorBoundary fallback={viewErrorFallback}>
355→              <div className="space-y-2">
356→                <div className="flex justify-end">
357→                  <SaveIndicator
358→                    isSaving={messageEdits.isSaving}
359→                    hasEdits={hasEdits}
360→                  />
361→                </div>
362→                <ReaderView
363→                  activeRules={rules.activeRules}
364→                  conversation={resolvedConversation}
365→                  adjustModeEnabled={session.adjustModeEnabled}
366→                  effectsMap={readerEffectsMap}
367→                  highlightedRuleId={rules.hoveredRuleId}
368→                  selectedBlock={
369→                    view === "reader" ? session.activeSelection : null
370→                  }
371→                  onSelectBlock={session.handleSelectionChange}
372→                  deletedMessageIds={deletion.deletedMessageIds}
373→                  showDeleted={deletion.showDeleted}
374→                  onBlocksChange={handleBlocksChange}
375→                  onDeleteMessage={handleDeleteMessage}
376→                  onDeleteRound={handleDeleteRound}
377→                  onRestoreMessage={deletion.restoreMessage}
378→                />
379→              </div>
380→            </ErrorBoundary>
381→          ) : view === "markdown" ? (
382→            <ErrorBoundary fallback={viewErrorFallback}>
383→              <MarkdownView
384→                activeRules={rules.activeRules}
385→                content={displayedMarkdown}
386→                adjustModeEnabled={session.adjustModeEnabled}
387→                highlightedRuleId={rules.hoveredRuleId}
388→                selectedRange={session.activeSelection}
389→                onSelectLines={session.handleSelectionChange}
390→              />
391→            </ErrorBoundary>
392→          ) : (
393→            <ErrorBoundary fallback={viewErrorFallback}>
394→              <ArtifactView content={artifact} />
395→            </ErrorBoundary>
396→          )}
397→
398→          {session.showGuide ? (
399→            <AdjustmentModeGuide
400→              view={view}
401→              onDismiss={() => session.setGuideDismissed(true)}
402→            />
403→          ) : null}
404→
405→          <ErrorBoundary
406→            fallback={
407→              <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
408→                {miscLabels.adjustmentLoadError}
409→              </div>
410→            }
411→          >
412→            <AdjustmentPopover
413→              anchor={session.activeAnchor ?? null}
414→              containerRef={session.sectionRef}
415→              draftMessage={session.activeDraftMessage}
416→              error={session.activeSessionError}
417→              isLoading={session.activeSessionLoading || session.isDiscarding}
418→              isSubmitting={session.isSubmitting}
419→              open={
420→                showPopover &&
421→                Boolean(session.activeSelection) &&
422→                Boolean(session.activeAnchor)
423→              }
424→              sessionDetail={session.activeSessionDetail}
425→              showReply={session.replyVisible}
426→              view={view}
427→              onClose={handlePopoverClose}
428→              onDraftMessageChange={session.handleDraftMessageChange}
429→              onRejectLastChange={handleRejectLastChange}
430→              onSubmitMessage={session.handleSubmitMessage}
431→            />
432→          </ErrorBoundary>
433→        </div>
434→      )}
435→
436→      {deleteDialog && (
437→        <DeleteMessageDialog
438→          messagePreview={deleteDialog.preview}
439→          isRound={deleteDialog.isRound}
440→          onConfirm={(reason) => {
441→            void handleConfirmDelete(reason);
442→          }}
443→          onCancel={() => setDeleteDialog(null)}
444→        />
445→      )}
446→
447→      {deletionToast.toast && (
448→        <UndoToast
449→          message={deletionToast.toast.message}
450→          onUndo={() => {
451→            void handleUndoDelete();
452→          }}
453→          onDismiss={deletionToast.dismissToast}
454→        />
455→      )}
456→
457→      <VersionsModal
458→        open={versionsModalOpen}
459→        onOpenChange={setVersionsModalOpen}
460→        snapshots={snapshots.snapshots}
461→        activeSnapshotId={snapshots.activeSnapshot?.id ?? null}
462→        onActivate={(snapshotId) => {
463→          void snapshots.activate(snapshotId);
464→        }}
465→        onDeactivate={() => {
466→          void snapshots.deactivate();
467→        }}
468→        onCreate={(label) => {
469→          void snapshots.create(label);
470→        }}
471→        onRename={(snapshotId, label) => {
472→          void snapshots.rename(snapshotId, label);
473→        }}
474→        onDelete={(snapshotId) => {
475→          void snapshots.delete(snapshotId);
476→        }}
477→      />
478→    </section>
479→  );
480→}
